  reading:{id:"N5L10r1",title:"昨日の天気",passage:"昨日の天気はあまりよくなかったです。朝は雨が降りました。午後は曇りでした。風も強かったです。夕方、少し涼しくなりました。夜は寒かったです。でも、今日は晴れです。とても暖かいです。明日もいい天気でしょう。",targetWords:[{word:"よくなかったです",id:"N5L10v13"},{word:"寒かったです",id:"N5L10v6"}],questions:[
    {id:"rqN5L10-1",q:"昨日の朝はどんな天気でしたか。",o:["晴れ","雨","雪","曇り"],c:1,exp:"朝は雨が降りました。"},
    {id:"rqN5L10-2",q:"夜はどうでしたか。",o:["暑かった","涼しかった","寒かった","暖かかった"],c:2,exp:"夜は寒かったです。"},
    {id:"rqN5L10-3",q:"今日の天気はどうですか。",o:["雨","曇り","晴れ","雪"],c:2,exp:"今日は晴れです。"}
  ]},
  listening:[
    {id:"N5L10l1",audioText:"A：週末はどうでしたか。B：とても楽しかったです。友達と映画を見ました。",a:"週末はどうでしたか。",o:["つまらなかった","楽しかった","忙しかった","寂しかった"],c:1,exp:"とても楽しかったです。"},
    {id:"N5L10l2",audioText:"A：昨日のパーティーは面白かったですか。B：いいえ、あまり面白くなかったです。",a:"パーティーはどうでしたか。",o:["面白かった","面白くなかった","楽しかった","忙しかった"],c:1,exp:"あまり面白くなかったです。"}
  ],
  questions:[
    {id:"N5L10q1",dim:"grammar",type:"recall",difficulty:"easy",s:"映画は___。(was fun)",a:"楽しかったです",o:["楽しいです","楽しかったです","楽しかった","楽しいでした"],c:1,exp:"i-adj past: drop い + かったです.",linksTo:"N5L10g1"},
    {id:"N5L10q2",dim:"grammar",type:"recall",difficulty:"easy",s:"昨日は雨___。",a:"でした",o:["です","でした","だった","だ"],c:1,exp:"Noun past: でした.",linksTo:"N5L10g2"},
    {id:"N5L10q3",dim:"grammar",type:"recall",difficulty:"medium",s:"天気は___。(wasn't good)",a:"よくなかったです",o:["よくないです","よくなかったです","よくなかった","よくないでした"],c:1,exp:"i-adj past neg: くなかったです.",linksTo:"N5L10g1"},
    {id:"N5L10q4",dim:"vocab",type:"recognition",difficulty:"easy",s:"「美味しかった」の意味は？",a:"was delicious",o:["is delicious","was delicious","wasn't delicious","will be delicious"],c:1,exp:"美味しかった = was delicious.",linksTo:"N5L10v5"},
    {id:"N5L10q5",dim:"vocab",type:"recognition",difficulty:"easy",s:"「曇り」の読み方は？",a:"くもり",o:["くもり","はれ","ゆき","あめ"],c:0,exp:"曇り = くもり (cloudy).",linksTo:"N5L10v20"},
    {id:"N5L10q6",dim:"kanji",type:"recognition",difficulty:"easy",s:"「雨」の漢字の意味は？",a:"rain",o:["snow","rain","sky","wind"],c:1,exp:"雨 = rain.",linksTo:"N5L10k3"},
    {id:"N5L10q7",dim:"grammar",type:"recall",difficulty:"medium",s:"図書館は___。(was quiet)",a:"静かでした",o:["静かです","静かでした","静かだった","静かだでした"],c:1,exp:"na-adj past: でした.",linksTo:"N5L10g2"},
    {id:"N5L10q8",dim:"vocab",type:"recognition",difficulty:"easy",s:"「忙しかった」の意味は？",a:"was busy",o:["is busy","was busy","wasn't busy","will be busy"],c:1,exp:"忙しかった = was busy.",linksTo:"N5L10v23"},
    {id:"N5L10q9",dim:"vocab",type:"recall",difficulty:"medium",s:"夏は___。(was hot)",a:"暑かったです",o:["暑いです","暑かったです","暑かった","暑いでした"],c:1,exp:"暑い→暑かったです (i-adj past).",linksTo:"N5L10v7"},
    {id:"N5L10q10",dim:"kanji",type:"recognition",difficulty:"easy",s:"Which kanji means 'snow'?",a:"雪",o:["雨","雪","晴","曇"],c:1,exp:"雪 = snow.",linksTo:"N5L10k4"},
    {id:"N5L10q11",dim:"vocab",type:"recall",difficulty:"medium",s:"このカバンは___。(was expensive)",a:"高かったです",o:["高いです","高かったです","高かった","高いでした"],c:1,exp:"高い→高かったです (i-adj past).",linksTo:"N5L10v9"},
    {id:"N5L10q12",dim:"kanji",type:"recognition",difficulty:"easy",s:"「楽」の漢字の意味は？",a:"fun; easy",o:["busy","fun; easy","quiet","beautiful"],c:1,exp:"楽 = fun/easy.",linksTo:"N5L10k7"}
  ]
