  grammar:[
    {id:"N5L15g1",point:"〜ませんか (invitation: won't you ~?)",explanation:"Verb ます stem + ませんか = polite invitation. Not a question about ability — it's an invitation. 行きませんか = Won't you go? 食べませんか = Won't you eat?",examples:["一緒に映画を見ませんか。 (Won't you watch a movie with me?)","昼ごはんを食べませんか。 (Won't you have lunch?)","週末、テニスをやりませんか。 (Won't you play tennis this weekend?)"],listening:"ませんか = invitation. Reply: いいですね (sounds good) or ちょっと… (maybe another time).",production:"Invite someone to 3 activities using 〜ませんか."},
    {id:"N5L15g2",point:"〜ましょう / 〜ましょうか (let's ~ / shall I ~?)",explanation:"Verb ます stem + ましょう = let's ~ (inclusive). 〜ましょうか = shall I ~? (offer to help). 食べましょう (let's eat), 手伝いましょうか (shall I help?).",examples:["食べましょう。 (Let's eat.)","一緒に行きましょう。 (Let's go together.)","荷物を持ちましょうか。 (Shall I carry your bag?)"],listening:"ましょう = let's (we together). ましょうか = shall I (offer).",production:"Make 3 'let's' sentences and 3 'shall I help' sentences."}
  ],
