  grammar:[
    {id:"N5L23g1",point:"Honorific speech (尊敬語)",explanation:"Elevates the subject (usually superior). Special verbs: いらっしゃる (go/come/be), おっしゃる (say), ご覧になる (see), 召し上がる (eat/drink). Pattern: お + verb stem + になる.",examples:["先生はいらっしゃいますか。 (Is the teacher here?)","社長がおっしゃいました。 (The president said.)","お客様が召し上がりました。 (The guest ate.)"],listening:"Honorific = elevates subject. Use for superiors' actions.",production:"Make 3 honorific sentences about a teacher's actions."},
    {id:"N5L23g2",point:"Humble speech (謙譲語)",explanation:"Lowers the speaker's actions to show respect to listener. Special verbs: 伺う (visit/ask), 申し上げる (say), 拝見する (see), 参る (go/come), 致す (do), いただく (receive). Pattern: お + verb stem + する.",examples:["明日伺います。 (I'll visit tomorrow — humble.)","拝見します。 (I'll look — humble.)","私が致します。 (I'll do it — humble.)"],listening:"Humble = lowers speaker's action. Use for your actions toward superiors.",production:"Make 3 humble sentences about your own actions."}
  ],
